  ('medical-tech-moex-13492', 'medical-tech', 'medical-tech-moex-101-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '下列抗病毒藥物中，除了何者以外，均是抑制病毒複製酵素（polymerase）？', '["Acyclovir", "Indinavir", "Ganciclovir", "Cidofovir"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:48+00:00", "source_pdf_sha1": "3ab453265bd0", "answer_pdf_sha1": "4e66b5515727", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "104", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
